API_name: nchu_course_search_by_department
Description:
{
  "description": "依開課系所搜尋課程。",
  "required_parameters": [
    {
      "name": "department",
      "type": "STRING",
      "description": "Department name to search for (e.g., 資工系, 文學院, 管理學院)"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "Maximum number of results to return (default: 20)",
      "default": 20
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "Semester code. If not specified, uses the latest semester.",
      "default": null
    }
  ]
}

